class Solution:
    def solve(self, nums: List[int], threshold: int) -> int:
        l, r = 1, max(nums)
        def compute(d):
            return sum(math.ceil(n/d) for n in nums)
        while l <= r:
            mid = (l + r) // 2
            if compute(mid) <= threshold: r = mid - 1
            else: l = mid + 1
        return l

